CREATE TRIGGER [Global].[Unit_History]ON [Global].[Unit]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.UnitId IS NOT NULL AND d.UnitId IS NULL THEN 'I' 		WHEN i.UnitId IS NOT NULL AND d.UnitId IS NOT NULL THEN 'U' 		WHEN i.UnitId IS NULL AND d.UnitId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.UnitId = d.UnitId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.Global_Unit([UnitId], [PlantId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [UnitId], [PlantId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.Global_Unit([UnitId], [PlantId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [UnitId], [PlantId], [Name], [DisplayName], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND